document.addEventListener("DOMContentLoaded",function(){const filtrosModalidade=document.querySelectorAll(".filtro-modalidade");const precos={corrida:{essencial:{mensal:240,trimestral:220,semestral:200},premium:{mensal:320,trimestral:305,semestral:290}},triathlon:{essencial:{mensal:380,trimestral:360,semestral:340},premium:{mensal:450,trimestral:435,semestral:420}}};const totais={corrida:{essencial:{trimestral:660,semestral:1200},premium:{trimestral:915,semestral:1740}},triathlon:{essencial:{trimestral:1080,semestral:2040},premium:{trimestral:1305,semestral:2520}}};filtrosModalidade.forEach(filtro=>{filtro.addEventListener("click",function(){filtrosModalidade.forEach(f=>f.classList.remove("ativo"));this.classList.add("ativo");const modalidade=this.getAttribute("data-modalidade");atualizarPrecos(modalidade)})});function inicializarCardsPeriodo(){const periodoCards=document.querySelectorAll(".periodo-card");periodoCards.forEach(card=>{card.addEventListener("click",function(){periodoCards.forEach(c=>c.classList.remove("ativo"));this.classList.add("ativo");const periodo=this.getAttribute("data-periodo");atualizarBotoesContratacao(periodo)})})}function atualizarBotoesContratacao(periodo){document.querySelectorAll(".periodo-botao").forEach(botao=>{botao.style.display="none"});document.querySelectorAll(`.periodo-botao[data-periodo="${periodo}"]`).forEach(botao=>{botao.style.display="inline-block"})}function atualizarPrecos(modalidade){if(document.querySelector("#essencial-mensal-preco")){document.querySelector("#essencial-mensal-preco").textContent=`${precos[modalidade].essencial.mensal}`}if(document.querySelector("#essencial-trimestral-preco")){document.querySelector("#essencial-trimestral-preco").textContent=`${totais[modalidade].essencial.trimestral}`}if(document.querySelector("#essencial-trimestral-equivalente")){document.querySelector("#essencial-trimestral-equivalente").textContent=`Equivale a R$ ${precos[modalidade].essencial.trimestral}/mês`}if(document.querySelector("#essencial-semestral-preco")){document.querySelector("#essencial-semestral-preco").textContent=`${totais[modalidade].essencial.semestral}`}if(document.querySelector("#essencial-semestral-equivalente")){document.querySelector("#essencial-semestral-equivalente").textContent=`Equivale a R$ ${precos[modalidade].essencial.semestral}/mês`}if(document.querySelector("#premium-mensal-preco")){document.querySelector("#premium-mensal-preco").textContent=`${precos[modalidade].premium.mensal}`}if(document.querySelector("#premium-trimestral-preco")){document.querySelector("#premium-trimestral-preco").textContent=`${totais[modalidade].premium.trimestral}`}if(document.querySelector("#premium-trimestral-equivalente")){document.querySelector("#premium-trimestral-equivalente").textContent=`Equivale a R$ ${precos[modalidade].premium.trimestral}/mês`}if(document.querySelector("#premium-semestral-preco")){document.querySelector("#premium-semestral-preco").textContent=`${totais[modalidade].premium.semestral}`}if(document.querySelector("#premium-semestral-equivalente")){document.querySelector("#premium-semestral-equivalente").textContent=`Equivale a R$ ${precos[modalidade].premium.semestral}/mês`}const treinador=window.location.pathname.split("/").pop().replace(".html","");document.querySelectorAll(".essencial-link-mensal").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=essencial&treinador=${treinador}&periodo=mensal`});document.querySelectorAll(".essencial-link-trimestral").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=essencial&treinador=${treinador}&periodo=trimestral`});document.querySelectorAll(".essencial-link-semestral").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=essencial&treinador=${treinador}&periodo=semestral`});document.querySelectorAll(".premium-link-mensal").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=premium&treinador=${treinador}&periodo=mensal`});document.querySelectorAll(".premium-link-trimestral").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=premium&treinador=${treinador}&periodo=trimestral`});document.querySelectorAll(".premium-link-semestral").forEach(link=>{link.href=`../cadastro-unificado.html?modalidade=${modalidade}&plano=premium&treinador=${treinador}&periodo=semestral`})}const modalidadeAtiva=document.querySelector(".filtro-modalidade.ativo");if(modalidadeAtiva){const modalidade=modalidadeAtiva.getAttribute("data-modalidade");atualizarPrecos(modalidade);inicializarCardsPeriodo();const periodoAtivo=document.querySelector(".periodo-card.ativo");if(periodoAtivo){const periodo=periodoAtivo.getAttribute("data-periodo");atualizarBotoesContratacao(periodo)}}});